module RefModule(
    input clk,
    input reset,
    input load,
    input [7:0] data_in,
    output reg [7:0] data_out);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset)
        data_out <= 8'b0;
    else if (load)
        data_out <= data_in;
end
endmodule
